const PROPHET_ELS = {
  modal: null, body: null,
};

function openProphetsModal() {
  if (!els.prophetsModal) return;
  buildProphetsModal();
  els.prophetsModal.classList.remove("hidden");
}
function closeProphetsModal() {
  if (els.prophetsModal) els.prophetsModal.classList.add("hidden");
}

function buildProphetsModal() {
  if (!els.prophetsBody) return;
  const body = els.prophetsBody;
  body.innerHTML = "";

  PROPHET_DATA.forEach((p, idx) => {
    const card = document.createElement("button");
    card.className = "prophetCard";
    card.type = "button";
    card.innerHTML = `
      <div class="prophetNum">${idx + 1}</div>
      <div class="prophetAr">${p.arabic}</div>
      <div class="prophetEn">${p.name}</div>
      ${p.surah ? `<div class="prophetSurah">Surah ${p.surah}</div>` : ""}
      <div class="prophetCount">${p.ayahs.length} ayat</div>`;
    card.addEventListener("click", () => selectProphet(p));
    body.appendChild(card);
  });
}

async function selectProphet(prophet) {
  closeProphetsModal();
  showLanding(false);
  setBadge("warn", `Loading ${prophet.name}…`);

  // Ensure all needed surahs are loaded
  const surahs = [...new Set(prophet.ayahs.map(id => id.split(":")[0]))];
  await Promise.all(surahs.map(s => ensureSurahLoaded(s).catch(() => {})));

  const records = prophet.ayahs.map(id => state.quranById.get(id)).filter(Boolean);

  if (els.mainQuery) els.mainQuery.value = prophet.name;
  state.selectedAyahId = null;
  setDetailState("empty");
  updateTabCounts(0, 0, 0, 0);
  renderResults(records);
  if (els.searchHint) els.searchHint.textContent =
    `Showing ${records.length} ayat about ${prophet.name} (${prophet.arabic})`;
  setBadge("ok", `${records.length} ayat · ${prophet.name}`);
}

